int main() {
    int a[6];
    a[0] = 34;
    a[1] = 12;
    a[2] = 45;
    a[3] = 7;
    a[4] = 23;
    a[5] = 18;
    int n = 6;
    int i = 0;
    while (i < n) {
        int j = 0;
        while (j < n - 1 - i) {
            int aj = a[j];
            int aj1 = a[j + 1];
            if (aj > aj1) {
                a[j] = aj1;
                a[j + 1] = aj;
            }
            j += 1;
        }
        i += 1;
    }
    return a[0];
}
